import { buildPortalView } from "./portal-view.mjs";

// Activate the at-risk strategic-account escalation against the document-shaped
// collections: persist workflow state, route one owner task per owner group,
// post a customer-safe message, and record a customer-visible audit event.
export function applyBenchmarkTask(db, now) {
  const request = db.workflow_requests[0];
  const timestamp = now;
  // Owner review window opens four hours after activation.
  const dueAt = new Date(new Date(timestamp).getTime() + 4 * 60 * 60 * 1000).toISOString();

  db.workflow_state = db.workflow_state.filter((item) => item.requestId !== request._id);
  db.workflow_state.push({
    _id: `state-${request._id}`,
    requestId: request._id,
    accountId: request.accountId,
    taskId: request.taskId,
    title: request.title,
    status: request.expectedOutcome,
    nextStep: request.nextStep,
    ownerGroups: request.ownerGroups,
    riskSignals: request.riskSignals.map((signal) => ({
      name: signal.name,
      detail: signal.detail
    })),
    activatedAt: timestamp,
    updatedAt: timestamp
  });

  db.owner_tasks = db.owner_tasks.filter((item) => item.requestId !== request._id);
  request.ownerGroups.forEach((ownerGroup, index) => {
    db.owner_tasks.push({
      _id: `task-${request._id}-${index + 1}`,
      requestId: request._id,
      accountId: request.accountId,
      ownerGroup,
      title: `${ownerGroup} recovery actions for ${request.title}`,
      status: "open",
      dueAt,
      createdAt: timestamp
    });
  });

  db.customer_messages = db.customer_messages.filter((item) => item.requestId !== request._id);
  db.customer_messages.push({
    _id: `msg-${request._id}`,
    requestId: request._id,
    accountId: request.accountId,
    body: request.customerMessage,
    customerVisible: true,
    sentAt: timestamp
  });

  db.audit_events.push({
    _id: `audit-${request._id}-${db.audit_events.length + 1}`,
    requestId: request._id,
    accountId: request.accountId,
    event: "escalation.activated",
    summary: request.expectedOutcome,
    ownerGroups: request.ownerGroups,
    customerVisible: true,
    occurredAt: timestamp
  });

  return buildPortalView(db);
}

import { buildPortalView } from "./portal-view.mjs";

const ESCALATION_STATUS =
  "At-risk escalation active with executive recovery owner routing and customer-visible audit history.";

const CUSTOMER_SAFE_MESSAGE =
  "We have activated the recovery plan for your delayed order and are coordinating updates through the portal.";

const COORDINATION_GROUPS = ["Customer Success", "Legal", "Finance", "Support"];

const OWNER_TASK_HORIZON_HOURS = {
  "Customer Success": 4,
  Support: 8,
  Finance: 24,
  "Executive Sponsor": 12,
  Legal: 24
};

const DEFAULT_TASK_HORIZON_HOURS = 24;

export function applyBenchmarkTask(db, now) {
  const request = db.workflow_requests?.[0];
  if (!request) {
    return buildPortalView(db);
  }

  const account = db.accounts?.find((item) => item._id === request.accountId) ?? db.accounts?.[0] ?? null;
  const at = now ?? db.benchmark_fixture?.generatedAt ?? new Date().toISOString();
  const ownerGroups = [...(request.ownerGroups ?? [])];
  const recoveryOwner = ownerGroups[ownerGroups.length - 1] ?? "Executive Sponsor";
  const activities = (db.activities ?? [])
    .filter((item) => item.subjectId === request._id)
    .sort((left, right) => new Date(left.occurredAt) - new Date(right.occurredAt));
  const riskSignals = (request.riskSignals ?? []).map((signal) => ({
    name: signal.name,
    detail: signal.detail,
    raisedAt: at
  }));
  const activityTimeline = activities.map((activity, index) => ({
    activityId: activity._id,
    summary: activity.summary,
    occurredAt: activity.occurredAt,
    sequence: index + 1,
    customerVisible: false
  }));
  const customerVisibleTimelineEntry = {
    _id: `audit-${request._id}-customer-visible`,
    eventType: "customer-visible-status",
    summary: request.expectedOutcome ?? ESCALATION_STATUS,
    actor: "workflow-engine",
    ownerGroups: [...ownerGroups],
    coordinationGroups: [...COORDINATION_GROUPS],
    riskSignals: riskSignals.map((signal) => signal.name),
    occurredAt: at,
    customerVisible: true,
    sequence: activityTimeline.length + 1
  };
  const auditTimeline = [...activityTimeline, customerVisibleTimelineEntry];
  const workflowState = {
    _id: `state-${request._id}`,
    requestId: request._id,
    accountId: request.accountId,
    taskId: request.taskId,
    title: request.title,
    status: request.expectedOutcome ?? ESCALATION_STATUS,
    nextStep: "Customer Success, Legal, Finance, and Support to confirm the recovery plan by 16:00 UTC.",
    recoveryOwner,
    accountTier: account?.tier ?? null,
    healthScore: account?.context?.healthScore ?? null,
    ownerGroups: [...ownerGroups],
    riskSignals,
    routing: {
      ownerGroups: [...ownerGroups],
      coordinationGroups: [...COORDINATION_GROUPS],
      executiveRecoveryOwner: recoveryOwner
    },
    context: account
      ? {
          account: {
            accountId: account._id,
            name: account.name,
            tier: account.tier,
            region: account.region
          },
          contract: { ...account.contract },
          support: {
            supportPlan: account.contract?.supportPlan ?? null,
            openCases: account.context?.openCases ?? null,
            contacts: (account.contacts ?? []).map((contact) => ({
              contactId: contact.contactId,
              role: contact.role,
              email: contact.email
            }))
          },
          invoice: {
            risk: account.context?.invoiceRisk ?? null,
            exposureCents: account.contract?.arrCents ?? null
          },
          usage: {
            healthScore: account.context?.healthScore ?? null,
            usageTrend: account.context?.usageTrend ?? null
          },
          shipment: {
            status: "delayed",
            priority: "high-value",
            orderType: "high-value order"
          },
          regulatory: {
            complianceFlags: [...(account.context?.complianceFlags ?? [])],
            legalReview: true
          },
          audit: {
            customerVisible: true,
            activityIds: activityTimeline.map((item) => item.activityId),
            timeline: auditTimeline
          }
        }
      : null,
    auditTimeline,
    openedAt: at,
    updatedAt: at
  };
  const ownerTasks = ownerGroups.map((ownerGroup, index) => ({
    _id: `task-${request._id}-${index + 1}`,
    requestId: request._id,
    accountId: request.accountId,
    ownerGroup,
    title: `${ownerGroup} recovery action for ${request.title}`,
    status: "open",
    dueAt: addHours(at, OWNER_TASK_HORIZON_HOURS[ownerGroup] ?? DEFAULT_TASK_HORIZON_HOURS),
    createdAt: at
  }));
  const customerMessage = {
    _id: `msg-${request._id}`,
    requestId: request._id,
    accountId: request.accountId,
    channel: "portal",
    visibility: "customer",
    audience: "customer",
    customerSafe: true,
    body: CUSTOMER_SAFE_MESSAGE,
    createdAt: at
  };
  const auditEvents = [
    ...activityTimeline.map((item) => ({
      _id: `audit-${item.activityId}`,
      requestId: request._id,
      accountId: request.accountId,
      subjectId: request._id,
      type: "account.activity.logged",
      summary: item.summary,
      occurredAt: item.occurredAt,
      customerVisible: false,
      sequence: item.sequence
    })),
    {
      _id: `audit-${request._id}-customer-visible`,
      requestId: request._id,
      accountId: request.accountId,
      subjectId: request._id,
      type: "customer-visible-status",
      summary: request.expectedOutcome ?? ESCALATION_STATUS,
      actor: "workflow-engine",
      ownerGroups: [...ownerGroups],
      coordinationGroups: [...COORDINATION_GROUPS],
      riskSignals: riskSignals.map((signal) => signal.name),
      customerVisible: true,
      occurredAt: at,
      sequence: auditTimeline.length
    }
  ];

  db.workflow_state = replaceByRequestId(db.workflow_state, request._id, [workflowState]);
  db.owner_tasks = replaceByRequestId(db.owner_tasks, request._id, ownerTasks);
  db.customer_messages = replaceByRequestId(db.customer_messages, request._id, [customerMessage]);
  db.audit_events = replaceByRequestId(db.audit_events, request._id, auditEvents);

  return buildPortalView(db);
}

function replaceByRequestId(collection, requestId, records) {
  const existing = collection ?? [];
  return existing.filter((item) => item.requestId !== requestId).concat(records);
}

function addHours(iso, hours) {
  const date = new Date(iso);
  date.setUTCHours(date.getUTCHours() + hours);
  return date.toISOString();
}

